// Criar diretório temporário e sanitizar narração para TTS
const fs = require('fs');
const data = $input.first().json.audioData || $input.first().json;

const videoId = data.videoId;
const tempDir = `${process.env.TEMP_DIR || '/data/temp'}/${videoId}`;

fs.mkdirSync(tempDir, { recursive: true });

let narracao = data.narracao || data.script?.narracao_completa || '';

// Sanitizar para TTS — remove elementos que causam pronúncia estranha
narracao = narracao
  .replace(/[\u{1F300}-\u{1FAFF}]/gu, '')  // emojis
  .replace(/[\u{2600}-\u{26FF}]/gu, '')     // símbolos miscelâneos
  .replace(/[\u{2700}-\u{27BF}]/gu, '')     // dingbats
  .replace(/[""«»„]/g, '"')               // aspas tipográficas
  .replace(/[''‛]/g, "'")                  // apóstrofos tipográficos
  .replace(/[—–]/g, ', ')                  // travessões → pausa natural
  .replace(/\*+/g, '')                     // asteriscos markdown
  .replace(/#{1,6}\s?/g, '')              // hashtags markdown
  .replace(/\[|\]/g, '')                   // colchetes
  .replace(/#/g, '')                       // # de hashtags (evita 'hashtag Jesus')
  .replace(/\s{2,}/g, ' ')                 // espaços múltiplos
  .trim();

return [{
  json: {
    videoId,
    narracao,
    tempDir,
    audioFile: `${tempDir}/narration.mp3`
  }
}];

const prevData = $('Prepare Audio Dir').first().json;

return [{
  json: {
    videoId: prevData.videoId,
    audioFile: prevData.audioFile,
    tempDir: prevData.tempDir,
    status: 'audio_ready'
  }
}];
